const feeds = [
  { url: 'https://feeds.elpais.com/mrss-s/pages/ep/site/elpais.com/section/economia/portada', name: 'El País', type: 'news' },
  { url: 'https://www.europapress.es/rss/rss.aspx?ch=136', name: 'Europa Press', type: 'news' },
  { url: 'https://cincodias.elpais.com/rss/feed.html?feedId=17066', name: 'Cinco Días', type: 'news' },
  { url: 'https://www.boe.es/rss/canal.php?c=ayudas', name: 'BOE Ayudas', type: 'boe' },
  { url: 'https://servicios.ine.es/wstempus/js/ES/DATOS_TABLA/25171?nult=3', name: 'INE IPC', type: 'ine' },
  { url: 'https://servicios.ine.es/wstempus/js/ES/DATOS_TABLA/24086?nult=3', name: 'INE Retail Sales', type: 'ine' },
  { url: 'https://news.google.com/rss/search?q=comercio+local+OR+retail+OR+pyme+OR+consumo+OR+ventas+minorista+site%3Aexpansion.com+OR+site%3Acincodias.elpais.com+OR+site%3Aeleconomista.es&hl=es&gl=ES&ceid=ES:es', name: 'Google News Retail', type: 'retail' },
  { url: 'https://www.mapa.gob.es/es/prensa/ultimas-noticias/default.aspx?rss=true', name: 'MAPA Alimentación', type: 'prices' },
  { url: 'https://www.facua.org/es/rss.php', name: 'FACUA Consumo', type: 'prices' },
  { url: 'https://news.google.com/rss/search?q=precios+proveedor+OR+coste+materias+primas+OR+mayorista+comercio+OR+inflacion+alimentacion+OR+costes+logistica&hl=es&gl=ES&ceid=ES:es', name: 'Google News Precios', type: 'prices' },
  { url: 'https://news.google.com/rss/search?q=apertura+tienda+OR+cierre+comercio+OR+nueva+franquicia+OR+competencia+retail+OR+centro+comercial+OR+promocion+descuento+comercio&hl=es&gl=ES&ceid=ES:es', name: 'Google News Competencia', type: 'competition' },
  { url: 'https://news.google.com/rss/search?q=oferta+empleo+comercio+OR+hosteleria+OR+tendencia+consumo+OR+habitos+compra+OR+ecommerce+tienda+fisica&hl=es&gl=ES&ceid=ES:es', name: 'Google News Tendencias', type: 'trends' }
];

const results = await Promise.all(feeds.map(async (feed) => {
  try {
    const resp = await fetch(feed.url, { signal: AbortSignal.timeout(15000) });
    return { ...feed, text: await resp.text(), ok: true };
  } catch (e) {
    console.log(`[Fetch] ${feed.name}: ${e.message}`);
    return { ...feed, text: '', ok: false, error: e.message };
  }
}));

let energyHtml = '';
try {
  const eresp = await fetch('https://www.esios.ree.es/es/pvpc', { signal: AbortSignal.timeout(15000) });
  energyHtml = await eresp.text();
} catch (e) { console.log(`[Energy] ESIOS: ${e.message}`); }

const byType = (t) => results.filter(r => r.type === t);
const textOf = (name) => results.find(r => r.name === name)?.text || '';

return [{ json: {
  newsXml: byType('news').map(r => r.text).join('\n'),
  boeXml: textOf('BOE Ayudas'),
  retailNewsXml: textOf('Google News Retail'),
  ineIpc: textOf('INE IPC'),
  ineRetailSales: textOf('INE Retail Sales'),
  energyHtml,
  mapaXml: textOf('MAPA Alimentación'),
  facuaXml: textOf('FACUA Consumo'),
  priceNewsXml: textOf('Google News Precios'),
  competitionXml: textOf('Google News Competencia'),
  trendsXml: textOf('Google News Tendencias'),
  feedStatus: results.map(r => ({ name: r.name, type: r.type, ok: r.ok, error: r.error || null }))
} }];

const usersResp = $('List Active Users').first().json;
if (!usersResp.ok || !Array.isArray(usersResp.users) || usersResp.users.length === 0) {
  return [{ json: { _skip: true, reason: 'No users after filter', count: 0 } }];
}
return usersResp.users.map(u => ({
  json: {
    user_id: u.user_id || u.id,
    business_name: u.business_name || '',
    business_type: u.business_type || '',
    city: u.city || '',
    sector: u.sector || 'comercio_local'
  }
}));

const shared = $('Fetch Shared Sources').first().json;
const items = $input.all();
const outputs = [];
const TODAY = new Date();
const TODAY_ISO = TODAY.toISOString().split('T')[0];
const MONTH = TODAY.getMonth();
const DOW = TODAY.getDay();

// ── UTILS (unchanged) ──────────────────────────────────────
function parseRSS(xml) {
  const out = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml || '')) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';
    const pubDate = (b.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
    out.push({ title: title.trim(), link: link.trim(), desc: desc.trim(), pubDate: pubDate.trim() });
  }
  return out;
}
function strip(s = '') { return String(s).replace(/<[^>]*>/g, ' ').replace(/&[a-z]+;/gi, ' ').replace(/\s+/g, ' ').trim(); }
function safeIsoDate(raw) { try { return raw ? new Date(raw).toISOString().split('T')[0] : TODAY_ISO; } catch { return TODAY_ISO; } }
function normalizeKey(v) { return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase(); }
function iso(d) { return d.toISOString().split('T')[0]; }
function addDays(d, n) { return new Date(d.getTime() + n * 86400000); }
function b64id(s) { return Buffer.from(s || 'x').toString('base64').slice(0, 12); }

// ── KEYWORDS (unchanged) ──────────────────────────────────
function buildKeywordSet(config) {
  const base = ['comercio local','pyme','autonomo','autónomo','hosteleria','hostelería','subvencion','subvención','digitalizacion','digitalización','kit digital','iva','energia','energía','alquiler','empleo','consumo','proveedores','margen','beneficio','coste','precio','facturacion','facturación','venta'];
  const dynamic = [...(config.keywords || []), ...(config.rss_filter_hints || []), config.business_type, config.city].filter(Boolean);
  return [...new Set([...base, ...dynamic].map(normalizeKey).filter(Boolean))];
}
function scoreText(text, keywords) {
  const normalized = normalizeKey(text);
  let score = 0;
  for (const kw of keywords) { if (normalized.includes(kw)) score += kw.length > 8 ? 4 : 2; }
  return Math.min(score, 10);
}

// ── PARSE NEWS (unchanged) ─────────────────────────────────
function parseNews(config) {
  const keywords = buildKeywordSet(config);
  return parseRSS(shared.newsXml || '').map(item => {
    const src = item.link.includes('elpais') ? 'El País' : item.link.includes('europapress') ? 'Europa Press' : item.link.includes('cincodias') ? 'Cinco Días' : 'Prensa';
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return { id: 'news_' + b64id(item.link || item.title), title: strip(item.title), summary: strip(item.desc).slice(0, 320), source: src, url: item.link, date: safeIsoDate(item.pubDate), category: 'noticias', relevance, tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8) };
  }).filter(n => n.relevance >= 3).sort((a, b) => b.relevance - a.relevance).slice(0, 15);
}
function parseRetailNews(config, xml) {
  const keywords = buildKeywordSet(config);
  return parseRSS(xml || '').map(item => {
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return { id: 'retail_' + b64id(item.link || item.title), title: strip(item.title), summary: strip(item.desc).slice(0, 320), source: 'Google News Retail', url: item.link, date: safeIsoDate(item.pubDate), category: 'retail', relevance, tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8) };
  }).filter(n => n.relevance >= 2).sort((a, b) => b.relevance - a.relevance).slice(0, 10);
}

// ── BOE (unchanged) ────────────────────────────────────────
function parseBoe(config) {
  const keywords = buildKeywordSet(config);
  const boeItems = parseRSS(shared.boeXml || '');
  const subsidies = [], regulations = [];
  for (const item of boeItems) {
    const text = `${item.title} ${item.desc}`;
    const normalized = normalizeKey(text);
    if (!keywords.some(kw => normalized.includes(kw))) continue;
    const common = { id: b64id(item.link || item.title), title: strip(item.title), summary: strip(item.desc).slice(0, 300), url: item.link };
    if (/(ley|reglamento|obligacion|obligación|normativa|sancion|sanción)/i.test(text)) {
      regulations.push({ id: `reg_${common.id}`, title: common.title, type: 'normativa', summary: common.summary, url: common.url, impact: /(obligacion|obligación|sancion|sanción)/i.test(text) ? 'high' : 'medium', action_required: 'Revisar requisitos, plazos y adaptación operativa' });
    } else {
      subsidies.push({ id: `sub_${common.id}`, title: common.title, type: /formacion|formación/i.test(text) ? 'formación' : /subvencion|subvención/i.test(text) ? 'subvención' : 'ayuda', amount_range: '', deadline: '', target: 'Pymes y autónomos', url: common.url, status: 'abierta' });
    }
  }
  return { subsidies: subsidies.slice(0, 10), regulations: regulations.slice(0, 10) };
}

// ── INE / ENERGY (unchanged) ───────────────────────────────
function processIneData(shared) {
  const signals = [];
  const fecha = new Date().toISOString();
  function parseIneSeries(data, label) {
    if (!Array.isArray(data)) return;
    for (const serie of data.slice(0, 15)) {
      const nombre = (serie.Nombre || '').replace(/<[^>]*>/g, '').trim();
      const datos = serie.Data || [];
      if (!nombre || datos.length === 0) continue;
      const ultimo = datos[0].Valor;
      const penultimo = datos.length > 1 ? datos[1].Valor : null;
      const variacion = (ultimo != null && penultimo != null && penultimo !== 0) ? ((ultimo - penultimo) / penultimo * 100).toFixed(2) : '0';
      signals.push({ name: nombre.substring(0, 150), value: ultimo, previous_value: penultimo, variation_pct: parseFloat(variacion), unit: 'index', source: label, description: `${nombre} — Var: ${variacion}%`, captured_at: fecha });
    }
  }
  try { parseIneSeries(typeof shared.ineIpc === 'string' ? JSON.parse(shared.ineIpc) : shared.ineIpc, 'INE-IPC'); } catch {}
  try { parseIneSeries(typeof shared.ineRetailSales === 'string' ? JSON.parse(shared.ineRetailSales) : shared.ineRetailSales, 'INE-Ventas-Retail'); } catch {}
  return signals;
}
function processEnergy(shared) {
  const html = shared.energyHtml || '';
  const signals = [];
  const fecha = new Date().toISOString();
  const precioMatch = html.match(/(?:precio medio|media)[^0-9]{0,80}?(\d{1,4}[.,]\d{1,4})\s*(?:€\/(?:MWh|kWh)|cts)/i) || html.match(/(\d{1,3}[.,]\d{2,4})\s*€\/MWh/i);
  if (precioMatch) {
    signals.push({ name: 'electricidad_pvpc_media', value: parseFloat(precioMatch[1].replace(',', '.')), unit: 'EUR/MWh', source: 'ESIOS-REE', description: 'Precio medio PVPC electricidad hoy', captured_at: fecha });
  }
  return signals;
}

// ── RETAIL PRICE RADAR (unchanged) ─────────────────────────
function buildRetailPriceRadar(config, shared) {
  const keywords = buildKeywordSet(config);
  const priceKw = [...new Set([...keywords, ...['precio', 'coste', 'proveedor', 'mayorista', 'margen', 'inflacion', 'iva', 'tarifa', 'materia prima', 'logistica', 'transporte', 'alquiler', 'envase', 'embalaje', 'suministro', 'distribucion'].map(normalizeKey)])];
  const signals = [];
  function processFeed(xml, sourceName, defaultType) {
    for (const item of parseRSS(xml || '').slice(0, 12)) {
      const text = `${item.title} ${item.desc}`;
      const score = scoreText(text, priceKw);
      if (score < 2) continue;
      const ntext = normalizeKey(text);
      let type = defaultType;
      if (/(proveedor|mayorista|suministro|distribucion|logistica|transporte)/.test(ntext)) type = 'supply_chain';
      else if (/(precio|coste|tarifa|inflacion|iva|margen)/.test(ntext)) type = 'price_intelligence';
      else if (/(fraude|alerta|retirada|sancion|denuncia)/.test(ntext)) type = 'consumer_alert';
      else if (/(tendencia|habito|consumo|demanda|estacional)/.test(ntext)) type = 'demand_signal';
      signals.push({ id: `pr_${b64id(item.link || item.title)}`, title: strip(item.title).slice(0, 200), summary: strip(item.desc).slice(0, 300), source: sourceName, url: item.link, type, relevance: score, impact: score >= 6 ? 'high' : score >= 4 ? 'medium' : 'low', date: safeIsoDate(item.pubDate), action_hint: type === 'price_intelligence' ? 'Revisar impacto en escandallo y márgenes' : type === 'supply_chain' ? 'Contactar proveedor o buscar alternativa' : type === 'consumer_alert' ? 'Verificar si afecta a tu negocio' : type === 'demand_signal' ? 'Ajustar stock u oferta según tendencia' : 'Evaluar relevancia' });
    }
  }
  processFeed(shared.mapaXml, 'MAPA-Alimentación', 'supply_chain');
  processFeed(shared.facuaXml, 'FACUA-Consumo', 'consumer_alert');
  processFeed(shared.priceNewsXml, 'Prensa-Precios', 'price_intelligence');
  return signals.sort((a, b) => b.relevance - a.relevance).slice(0, 20);
}

// ══════════════════════════════════════════════════════════
// NEW in v6.3: PRICE CATALOG — operational cost map per biz
// ══════════════════════════════════════════════════════════
function buildPriceCatalog(config, ineSignals, energySignals, priceRadar) {
  const bt = normalizeKey(config.business_type || '');

  // Map business types to their key cost lines
  const costProfiles = {
    food: { types: ['bar','cafeteria','restaurante','panaderia','fruteria','carniceria','supermercado','alimentacion','catering','pasteleria','heladeria','comida rapida'],
      lines: [
        { name: 'Materias primas alimentarias', ine_match: /(aliment|bebida|pan|carne|pescado|fruta|verdura|aceite|leche|huevo|cereales)/, weight: 0.35, category: 'producto' },
        { name: 'Bebidas', ine_match: /(bebida|alcohol|cerveza|vino|refresco)/, weight: 0.10, category: 'producto' },
        { name: 'Electricidad y gas', ine_match: null, energy: true, weight: 0.12, category: 'operativo' },
        { name: 'Alquiler del local', ine_match: /(alquiler|vivienda)/, weight: 0.15, category: 'fijo' },
        { name: 'Personal', ine_match: null, weight: 0.20, category: 'fijo' },
        { name: 'Envases y desechables', ine_match: /(envase|plastico|papel)/, weight: 0.03, category: 'operativo' },
        { name: 'Transporte y reparto', ine_match: /(transporte|combustible|carburante)/, weight: 0.05, category: 'operativo' }
      ]
    },
    fashion: { types: ['moda','ropa','zapateria','calzado','complementos','textil','boutique','lenceria'],
      lines: [
        { name: 'Compra de mercancía', ine_match: /(vestido|calzado|textil|confeccion)/, weight: 0.45, category: 'producto' },
        { name: 'Alquiler del local', ine_match: /(alquiler|vivienda)/, weight: 0.18, category: 'fijo' },
        { name: 'Personal', ine_match: null, weight: 0.15, category: 'fijo' },
        { name: 'Electricidad', ine_match: null, energy: true, weight: 0.06, category: 'operativo' },
        { name: 'Logística y envíos', ine_match: /(transporte|combustible)/, weight: 0.08, category: 'operativo' },
        { name: 'Marketing y escaparate', ine_match: null, weight: 0.05, category: 'operativo' },
        { name: 'Embalaje', ine_match: /(envase|papel)/, weight: 0.03, category: 'operativo' }
      ]
    },
    services: { types: ['peluqueria','estetica','fisioterapia','clinica','dental','veterinaria','taller','mecanico','lavanderia','tintoreria','gimnasio','academia','formacion'],
      lines: [
        { name: 'Productos/materiales profesionales', ine_match: /(quimico|farmaceut|higiene|cosmetico)/, weight: 0.15, category: 'producto' },
        { name: 'Alquiler del local', ine_match: /(alquiler|vivienda)/, weight: 0.20, category: 'fijo' },
        { name: 'Personal', ine_match: null, weight: 0.35, category: 'fijo' },
        { name: 'Electricidad y agua', ine_match: null, energy: true, weight: 0.10, category: 'operativo' },
        { name: 'Equipamiento y mantenimiento', ine_match: /(mueble|electrodomestico)/, weight: 0.08, category: 'operativo' },
        { name: 'Marketing', ine_match: null, weight: 0.05, category: 'operativo' },
        { name: 'Seguros y fiscal', ine_match: null, weight: 0.07, category: 'fijo' }
      ]
    },
    general: { types: [],
      lines: [
        { name: 'Compra de mercancía/producto', ine_match: null, weight: 0.35, category: 'producto' },
        { name: 'Alquiler del local', ine_match: /(alquiler|vivienda)/, weight: 0.18, category: 'fijo' },
        { name: 'Personal', ine_match: null, weight: 0.20, category: 'fijo' },
        { name: 'Electricidad', ine_match: null, energy: true, weight: 0.08, category: 'operativo' },
        { name: 'Logística', ine_match: /(transporte|combustible)/, weight: 0.07, category: 'operativo' },
        { name: 'Marketing', ine_match: null, weight: 0.05, category: 'operativo' },
        { name: 'Otros costes fijos', ine_match: null, weight: 0.07, category: 'fijo' }
      ]
    }
  };

  // Detect profile
  let profile = costProfiles.general;
  for (const [key, p] of Object.entries(costProfiles)) {
    if (key === 'general') continue;
    if (p.types.some(t => bt.includes(normalizeKey(t)))) { profile = p; break; }
  }

  // Build cost lines with real data
  const costLines = profile.lines.map(line => {
    const entry = { name: line.name, weight_pct: Math.round(line.weight * 100), category: line.category, trend: 'stable', variation_pct: 0, data_source: 'sin datos', last_update: TODAY_ISO, action: null };

    // Match against IPC signals
    if (line.ine_match) {
      const match = ineSignals.find(s => line.ine_match.test(normalizeKey(s.name)));
      if (match) {
        entry.variation_pct = match.variation_pct;
        entry.trend = match.variation_pct > 1 ? 'subiendo' : match.variation_pct < -1 ? 'bajando' : 'estable';
        entry.data_source = match.source;
        entry.index_value = match.value;
        if (match.variation_pct > 2) entry.action = `Coste subiendo ${match.variation_pct}%. Buscar alternativa o renegociar.`;
        else if (match.variation_pct < -2) entry.action = `Coste bajando ${Math.abs(match.variation_pct)}%. Oportunidad para mejorar margen.`;
      }
    }
    // Match energy
    if (line.energy && energySignals.length > 0) {
      const e = energySignals[0];
      entry.data_source = e.source;
      entry.current_value = `${e.value} ${e.unit}`;
      entry.trend = e.value > 100 ? 'caro' : e.value > 60 ? 'normal' : 'barato';
      if (e.value > 100) entry.action = 'Electricidad cara. Concentrar consumo en horas valle.';
      else if (e.value < 40) entry.action = 'Electricidad barata hoy. Buen momento para uso intensivo.';
    }
    // Match supply chain news
    const relatedNews = priceRadar.filter(s => {
      const sn = normalizeKey(s.title + ' ' + s.summary);
      const ln = normalizeKey(line.name);
      return ln.split(' ').some(w => w.length > 3 && sn.includes(w));
    });
    if (relatedNews.length > 0) {
      entry.related_news = relatedNews.slice(0, 2).map(n => ({ title: n.title.slice(0, 100), source: n.source, impact: n.impact }));
    }

    return entry;
  });

  // Margin pressure index: weighted sum of cost trends
  let pressureIndex = 0;
  let dataPoints = 0;
  for (const cl of costLines) {
    if (cl.variation_pct !== 0) {
      pressureIndex += cl.variation_pct * (cl.weight_pct / 100);
      dataPoints++;
    }
  }
  const pressureLevel = pressureIndex > 2 ? 'high' : pressureIndex > 0.5 ? 'medium' : pressureIndex < -0.5 ? 'favorable' : 'neutral';

  // Margin actions
  const marginActions = [];
  const risingCosts = costLines.filter(cl => cl.variation_pct > 1.5).sort((a, b) => b.variation_pct - a.variation_pct);
  const fallingCosts = costLines.filter(cl => cl.variation_pct < -1).sort((a, b) => a.variation_pct - b.variation_pct);

  if (risingCosts.length > 0) {
    marginActions.push({ type: 'protect', priority: 'high', action: `Revisar precio de venta en productos afectados por ${risingCosts[0].name} (+${risingCosts[0].variation_pct}%)`, detail: 'Si no puedes subir precio, reduce porción/gramaje o busca proveedor alternativo.', time_estimate: '30 min' });
  }
  if (fallingCosts.length > 0) {
    marginActions.push({ type: 'opportunity', priority: 'medium', action: `Aprovechar bajada en ${fallingCosts[0].name} (${fallingCosts[0].variation_pct}%)`, detail: 'Stockar a mejor precio, lanzar promoción con mejor margen, o mejorar calidad manteniendo precio.', time_estimate: '15 min decisión' });
  }
  if (pressureLevel === 'high') {
    marginActions.push({ type: 'urgent', priority: 'high', action: 'Revisión general de escandallos', detail: 'Presión de costes generalizada. Revisa los 5 productos de mayor venta y recalcula margen real.', time_estimate: '1 hora' });
  }

  return {
    profile_detected: Object.entries(costProfiles).find(([k, p]) => p === profile)?.[0] || 'general',
    cost_lines: costLines,
    margin_pressure: { index: Math.round(pressureIndex * 100) / 100, level: pressureLevel, data_points: dataPoints, interpretation: pressureLevel === 'high' ? 'Costes subiendo significativamente — proteger márgenes ya' : pressureLevel === 'medium' ? 'Ligera presión al alza — monitorizar' : pressureLevel === 'favorable' ? 'Costes bajando — oportunidad de mejorar margen o promocionar' : 'Costes estables — buen momento para optimizar operaciones' },
    margin_actions: marginActions,
    data_note: dataPoints === 0 ? 'Sin datos de variación de precios hoy. Se actualizará con los próximos datos del INE/ESIOS.' : `Basado en ${dataPoints} indicador(es) públicos del INE y ESIOS. No sustituye tu contabilidad real.`
  };
}

// ── COMPETITIVE INTEL (enhanced: counter-actions) ─────────
function buildCompetitiveIntel(config, shared) {
  const city = normalizeKey(config.city || '');
  const bt = normalizeKey(config.business_type || '');
  const bizName = config.business_name || 'Tu negocio';
  const compKw = [...new Set([city, bt, 'apertura', 'cierre', 'franquicia', 'expansion', 'centro comercial', 'promocion', 'descuento', 'oferta', 'competencia', 'tienda online', 'ecommerce'].filter(Boolean))];
  const trendKw = [...new Set([city, bt, 'tendencia', 'consumo', 'habito', 'compra', 'demanda', 'estacional', 'empleo comercio', 'hosteleria', 'turismo'].filter(Boolean))];
  const signals = [];

  for (const item of parseRSS(shared.competitionXml || '').slice(0, 15)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, compKw);
    if (score < 2) continue;
    const ntext = normalizeKey(text);
    let type = 'competitor_move';
    if (/(apertura|nueva|inaugur|franquicia|expansion)/.test(ntext)) type = 'new_competitor';
    else if (/(cierre|liquida|quiebra|traspaso)/.test(ntext)) type = 'competitor_exit';
    else if (/(promocion|descuento|oferta|rebaja|2x1|outlet)/.test(ntext)) type = 'competitor_promo';
    else if (/(centro comercial|gran superficie|marketplace|amazon)/.test(ntext)) type = 'big_retail_move';
    const isLocal = city && ntext.includes(city);

    const counterActions = {
      new_competitor: [
        `Refuerza tu comunicación: publica por qué ${bizName} es diferente`,
        'Lanza oferta de fidelización para tus clientes actuales',
        'Visita al nuevo competidor: conoce su oferta y precio'
      ],
      competitor_exit: [
        'Campaña inmediata: "Seguimos aquí para ti" en WhatsApp y redes',
        'Contacta a sus proveedores: puede haber stock o condiciones interesantes',
        'Si tenía buena ubicación, valora expansión o segundo punto'
      ],
      competitor_promo: [
        'NO bajes precios por reflejo. Enfatiza valor, no precio',
        `Publica testimonio de cliente satisfecho de ${bizName}`,
        'Si es promo agresiva temporal, aguanta sin reaccionar: volverán los precios normales'
      ],
      big_retail_move: [
        'Tu ventaja es cercanía, trato personal y flexibilidad',
        'Ofrece algo que la gran superficie no puede: personalización, urgencia, confianza',
        'Refuerza presencia digital local: Google Business, Instagram geolocalizado'
      ],
      competitor_move: ['Monitorizar y evaluar impacto en tu zona']
    };

    signals.push({
      id: `comp_${b64id(item.link || item.title)}`,
      title: strip(item.title).slice(0, 200),
      summary: strip(item.desc).slice(0, 300),
      source: 'Inteligencia-Competitiva', url: item.link, type,
      is_local: isLocal,
      relevance: isLocal ? Math.min(score + 3, 10) : score,
      date: safeIsoDate(item.pubDate),
      counter_actions: counterActions[type] || counterActions.competitor_move
    });
  }

  for (const item of parseRSS(shared.trendsXml || '').slice(0, 10)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, trendKw);
    if (score < 2) continue;
    signals.push({
      id: `trend_${b64id(item.link || item.title)}`,
      title: strip(item.title).slice(0, 200),
      summary: strip(item.desc).slice(0, 300),
      source: 'Tendencias-Consumo', url: item.link, type: 'consumer_trend',
      is_local: city ? normalizeKey(text).includes(city) : false,
      relevance: score, date: safeIsoDate(item.pubDate),
      counter_actions: ['Adapta tu oferta o comunicación a esta tendencia', 'Pregunta a tus clientes qué opinan']
    });
  }

  return signals.sort((a, b) => b.relevance - a.relevance).slice(0, 15);
}

// ── COST MONITOR (unchanged) ──────────────────────────────
function buildCostMonitor(config, ineSignals, energySignals, priceRadar) {
  const bt = normalizeKey(config.business_type || '');
  const alerts = [];
  const recommendations = [];
  for (const s of energySignals) {
    if (s.value > 100) alerts.push({ category: 'energia', severity: 'high', title: `Electricidad cara: ${s.value} ${s.unit}`, recommendation: 'Concentrar uso intensivo en horas valle. Revisar contrato eléctrico.' });
    else if (s.value > 60) alerts.push({ category: 'energia', severity: 'medium', title: `Electricidad moderada: ${s.value} ${s.unit}`, recommendation: 'Buen momento para operaciones intensivas en energía.' });
  }
  const foodTypes = ['bar', 'cafeteria', 'restaurante', 'panaderia', 'fruteria', 'carniceria', 'supermercado', 'alimentacion'];
  const isFoodBiz = foodTypes.some(t => bt.includes(normalizeKey(t)));
  for (const s of ineSignals) {
    const n = normalizeKey(s.name);
    if (Math.abs(s.variation_pct) < 0.5) continue;
    const rising = s.variation_pct > 0;
    if (isFoodBiz && /(aliment|bebida|pan|carne|pescado|fruta|verdura|aceite|leche|huevo)/.test(n)) {
      alerts.push({ category: 'costes_producto', severity: Math.abs(s.variation_pct) > 2 ? 'high' : 'medium', title: `${s.name}: ${rising ? '+' : ''}${s.variation_pct}%`, recommendation: rising ? 'Revisar precios de venta o buscar proveedor alternativo.' : 'Oportunidad para mejorar margen o hacer promoción.' });
    }
    if (/(alquiler|vivienda)/.test(n) && Math.abs(s.variation_pct) > 1) {
      alerts.push({ category: 'costes_local', severity: 'medium', title: `Alquileres: ${rising ? '+' : ''}${s.variation_pct}%`, recommendation: rising ? 'Si se acerca renovación, negociar con datos.' : 'Buen momento para renegociar.' });
    }
    if (/(transporte|combustible|carburante)/.test(n) && Math.abs(s.variation_pct) > 1) {
      alerts.push({ category: 'costes_logistica', severity: Math.abs(s.variation_pct) > 3 ? 'high' : 'medium', title: `Transporte: ${rising ? '+' : ''}${s.variation_pct}%`, recommendation: rising ? 'Agrupar pedidos. Revisar costes de reparto.' : 'Buen momento para stockar.' });
    }
  }
  for (const s of priceRadar.filter(s => s.impact === 'high')) {
    alerts.push({ category: 'proveedor', severity: 'high', title: s.title.slice(0, 120), recommendation: s.action_hint || 'Revisar impacto en cadena de suministro.' });
  }
  if (alerts.filter(a => a.severity === 'high').length >= 2) recommendations.push({ priority: 'high', action: 'Revisión urgente de escandallos y márgenes', detail: 'Varias alertas de costes altos simultáneas.' });
  if (alerts.some(a => a.category === 'energia' && a.severity === 'high')) recommendations.push({ priority: 'high', action: 'Optimizar consumo energético', detail: 'Electricidad cara hoy.' });
  return { alerts: alerts.slice(0, 15), recommendations: recommendations.slice(0, 8), summary: alerts.length === 0 ? 'Sin alertas de costes relevantes hoy.' : `${alerts.filter(a => a.severity === 'high').length} alerta(s) alta(s), ${alerts.filter(a => a.severity === 'medium').length} media(s).` };
}

