  }
  for (const sub of (context.radar.subsidies || []).slice(0, 3)) {
    tasks.push({ type: 'subsidy_check', title: `Ayuda: ${sub.title.slice(0, 80)}`, source: 'boe', priority: 'medium', due_date: TODAY_ISO, category: 'oportunidad', estimated_impact: 'Financiación potencial', time_estimate: '15 min', description: `${sub.type} — ${sub.target || 'Pymes'}` });
  }
  for (const signal of (context.market.price_signals || []).slice(0, 3)) {
    tasks.push({ type: 'price_review', title: `Precios: ${(signal.title || 'Señal').slice(0, 80)}`, source: 'market', priority: signal.impact === 'high' ? 'high' : 'medium', due_date: TODAY_ISO, category: 'proteger_margen', estimated_impact: 'Revisar precio final', time_estimate: '10 min', description: signal.summary || '' });
  }
  for (const email of (context.inbox.awaiting_reply || []).filter(e => e.priority !== 'high').slice(0, 3)) {
    tasks.push({ type: 'email_reply', title: `Responder: ${(email.subject || 'Email').slice(0, 80)}`, source: 'gmail', priority: 'medium', due_date: TODAY_ISO, category: 'operativo', estimated_impact: 'Relación cliente/proveedor', time_estimate: '3 min', description: email.suggested_reply || 'Pendiente' });
  }
  for (const reminder of (context.calendar.reminders || []).slice(0, 3)) {
    tasks.push({ type: 'calendar_action', title: (reminder.title || 'Recordatorio').slice(0, 80), source: 'google_calendar', priority: 'medium', due_date: reminder.date || TODAY_ISO, category: 'operativo', estimated_impact: 'Puntualidad', time_estimate: '5 min', description: reminder.notes || '' });
  }
  for (const camp of (context.marketing?.campaigns || []).filter(c => c.suggested_date === TODAY_ISO).slice(0, 2)) {
    tasks.push({ type: 'campaign_launch', title: `Lanzar: ${camp.title.slice(0, 80)}`, source: 'marketing', priority: 'medium', due_date: TODAY_ISO, category: 'vender_mas', estimated_impact: camp.expected_impact || 'Visibilidad', time_estimate: '15 min', description: `Canal: ${(camp.channel || []).join(', ')}` });
  }

  // Time summary
  const totalTime = tasks.reduce((sum, t) => {
    const m = (t.time_estimate || '').match(/(\d+)/);
    return sum + (m ? parseInt(m[1]) : 10);
  }, 0);

  tasks._time_summary = { total_estimated_minutes: totalTime, interpretation: totalTime <= 30 ? 'Día ligero — menos de media hora de tareas' : totalTime <= 60 ? 'Carga normal — 1 hora de tareas' : `Día intenso — ${Math.round(totalTime / 60)}h de tareas. Prioriza las de alta prioridad.` };

  return tasks.sort((a, b) => ({ high: 3, medium: 2, low: 1 }[b.priority] || 0) - ({ high: 3, medium: 2, low: 1 }[a.priority] || 0)).slice(0, 25);
}

// ── DAILY SUMMARY (enhanced: time estimate) ───────────────
function buildDailySummary(config, context) {
  const bizName = config.business_name || 'Tu negocio';
  const highTasks = (context.tasks || []).filter(t => t.priority === 'high');
  const medTasks = (context.tasks || []).filter(t => t.priority === 'medium');
  const costAlerts = (context.cost_monitor?.alerts || []).filter(a => a.severity === 'high').length;
  const compMoves = (context.competitive?.signals || []).filter(s => s.relevance >= 5).length;
  const opportunities = (context.radar.subsidies?.length || 0) + (context.competitive?.signals || []).filter(s => s.type === 'competitor_exit').length;
  const risks = (context.radar.regulations?.length || 0) + costAlerts + (context.reputation.reviews?.urgent?.length || 0);
  const totalTasks = (context.tasks || []).length;
  const timeSummary = context.tasks?._time_summary || {};

  let score = 60;
  score += Math.min((context.radar.news?.length || 0), 8);
  score += Math.min((context.radar.subsidies?.length || 0) * 3, 12);
  score += Math.min((context.marketing?.campaigns?.length || 0) * 2, 8);
  score += context.reputation.connected ? 5 : 0;
  score += context.inbox.connected ? 5 : 0;
  score += context.calendar.connected ? 3 : 0;
  score -= Math.min((context.reputation.reviews?.urgent?.length || 0) * 8, 24);
  score -= Math.min((context.radar.regulations?.length || 0) * 4, 16);
  score -= Math.min(costAlerts * 5, 15);
  score -= Math.min((context.inbox.awaiting_reply?.length || 0) * 3, 12);
  score = Math.max(0, Math.min(100, score));

  let headline = '';
  if (highTasks.length > 0) headline = `${highTasks.length} acción(es) urgente(s) para ${bizName}`;
  else headline = `${bizName}: día sin urgencias`;
  if (costAlerts > 0) headline += ` | ${costAlerts} alerta(s) de costes`;
  if (compMoves > 0) headline += ` | ${compMoves} movimiento(s) competencia`;
  if (opportunities > 0) headline += ` | ${opportunities} oportunidad(es)`;
  headline += '.';

  const top3 = highTasks.slice(0, 3).map(t => ({ action: t.title, why: t.estimated_impact || 'Impacto en negocio', category: t.category || 'general', time: t.time_estimate || '' }));

  const actions = [];
  if (highTasks.length > 0) actions.push(`🔴 ${highTasks.length} urgente(s) — impacto directo en ventas o margen`);
  if (costAlerts > 0) actions.push(`💰 ${costAlerts} alerta(s) de costes — revisar márgenes`);
  if ((context.reputation.reviews?.urgent || []).length > 0) actions.push(`⭐ ${context.reputation.reviews.urgent.length} reseña(s) negativa(s) — responder hoy`);
  if ((context.inbox.awaiting_reply || []).length > 0) actions.push(`📧 ${context.inbox.awaiting_reply.length} email(s) pendiente(s)`);
  if ((context.radar.regulations || []).length > 0) actions.push(`📋 ${context.radar.regulations.length} normativa(s) — revisar cumplimiento`);
  if ((context.marketing?.campaigns || []).length > 0) actions.push(`📣 ${context.marketing.campaigns.length} campaña(s) sugerida(s)`);
  if ((context.radar.subsidies || []).length > 0) actions.push(`💶 ${context.radar.subsidies.length} ayuda(s) disponible(s)`);

  const modulesOn = [context.inbox.connected && 'Gmail', context.calendar.connected && 'Calendar', context.reputation.connected && 'Reputación', context.sheets?.connected && 'Sheets'].filter(Boolean);
  const modulesOff = [!context.inbox.connected && 'Gmail', !context.calendar.connected && 'Calendar', !context.reputation.connected && 'Reputación', !context.sheets?.connected && 'Sheets'].filter(Boolean);

  return {
    headline,
    business_health_score: score,
    score_label: score >= 75 ? 'Buen día' : score >= 50 ? 'Día normal' : 'Día con riesgos',
    top_priorities: top3,
    time_to_complete: timeSummary.interpretation || '',
    estimated_minutes: timeSummary.total_estimated_minutes || 0,
    priority_actions: actions.slice(0, 10),
    opportunities_count: opportunities,
    risks_count: risks,
    tasks_total: totalTasks,
    tasks_high: highTasks.length,
    tasks_medium: medTasks.length,
    margin_pressure: context.price_catalog?.margin_pressure?.level || 'unknown',
    modules_connected: modulesOn,
    modules_pending: modulesOff,
    tip: modulesOff.length > 0
      ? `Conecta ${modulesOff.join(', ')} en tu panel ENLAZE para más automatización.`
      : 'Todos los módulos activos.'
  };
}

// ══════════════════════════════════════════════════════════
// MAIN LOOP
// ══════════════════════════════════════════════════════════
for (const item of items) {
  const config = item.json;
  if (config._skip) { outputs.push({ json: { ...config, skipped: true } }); continue; }

  const baseUrl = config._auth_base_url || 'https://enlaze.vercel.app';
  const agentKey = config._auth_key || '';
  if (!agentKey) console.log(`[WARN] No API key for user ${config.user_id}.`);

  // ── Public sources (always work) ──
  const radarNews = parseNews(config);
  const boe = parseBoe(config);
  const retailNews = parseRetailNews(config, shared.retailNewsXml || '');
  const ineSignals = processIneData(shared);
  const energySignals = processEnergy(shared);
  const priceRadar = buildRetailPriceRadar(config, shared);
  const competitive = { signals: buildCompetitiveIntel(config, shared) };
  const price_catalog = buildPriceCatalog(config, ineSignals, energySignals, priceRadar);

  // ── Backend modules ──
  const modules = config.agent_modules_enabled || {};
  const gmailOn = Boolean(config.gmail_connected || modules.gmail);
  const calendarOn = Boolean(config.google_calendar_connected || modules.calendar);
  const businessOn = Boolean(config.google_business_connected || config.google_place_id || modules.reputation);
  const marketOn = Boolean(modules.market || true);
  const sheetsOn = Boolean(config.google_sheets_connected || modules.sheets);

  const [gmailResp, calendarResp, reputationResp, marketResp, sheetsResp] = await Promise.all([
    gmailOn ? callModule(baseUrl, agentKey, `/api/agent/gmail/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    calendarOn ? callModule(baseUrl, agentKey, `/api/agent/calendar/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    businessOn ? callModule(baseUrl, agentKey, `/api/agent/reputation/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    marketOn ? callModule(baseUrl, agentKey, `/api/agent/market/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false }),
    sheetsOn ? callModule(baseUrl, agentKey, `/api/agent/sheets/summary?user_id=${encodeURIComponent(config.user_id)}`) : Promise.resolve({ ok: false })
  ]);

  const inbox = gmailResp.ok && gmailResp.data ? { connected: true, ...gmailResp.data } : defaultInbox();
  const calendar = calendarResp.ok && calendarResp.data ? { connected: true, ...calendarResp.data } : defaultCalendar();
  const reputation = reputationResp.ok && reputationResp.data ? { connected: true, ...reputationResp.data } : defaultReputation();
  const market = marketResp.ok && marketResp.data ? { connected: true, ...marketResp.data } : defaultMarket();
  const sheets = sheetsResp.ok && sheetsResp.data ? { connected: true, ...sheetsResp.data } : defaultSheets();

  // ── Enrich market ──
  market.ine_signals = ineSignals;
  market.energy_signals = energySignals;
  market.retail_price_radar = priceRadar;
  market.cost_alerts = [...energySignals.filter(s => s.value != null), ...ineSignals.filter(s => Math.abs(s.variation_pct) > 1)].slice(0, 10);
  market.price_signals = [...(market.price_signals || []), ...priceRadar.filter(s => s.type === 'price_intelligence').map(s => ({ title: s.title, summary: s.summary, source: s.source, impact: s.impact }))].slice(0, 15);
  market.supplier_alerts = [...(market.supplier_alerts || []), ...priceRadar.filter(s => s.type === 'supply_chain').map(s => ({ title: s.title, summary: s.summary, source: s.source, impact: s.impact }))].slice(0, 10);

  const allNews = [...radarNews, ...retailNews].sort((a, b) => b.relevance - a.relevance);
  const uniqueNews = Array.from(new Map(allNews.map(n => [normalizeKey(n.title), n])).values()).slice(0, 20);

  const radar = {
    news: uniqueNews,
    regulations: boe.regulations,
    subsidies: boe.subsidies,
    competitor_signals: [...(market.competitor_signals || []), ...competitive.signals.filter(s => s.type !== 'consumer_trend')],
    local_events: market.market_signals || [],
    consumer_trends: competitive.signals.filter(s => s.type === 'consumer_trend')
  };

  const cost_monitor = buildCostMonitor(config, ineSignals, energySignals, priceRadar);
  const ctx = { inbox, calendar, reputation, market, radar, competitive, cost_monitor, price_catalog };
  const campaigns = buildCampaigns(config, ctx);
  ctx.marketing = { campaigns };
  const tasks = buildActionableTasks(config, ctx);
  ctx.tasks = tasks;
  const recommendations = buildBusinessRecommendations(config, ctx);

  // ── Automation status (cleaner) ──
  const automation = {
    works_now: {
      description: 'Módulos que funcionan sin configuración adicional',
      modules: ['radar_noticias', 'radar_normativo', 'radar_ayudas', 'inteligencia_competitiva', 'cost_monitor', 'price_catalog', 'price_radar', 'campanas_sugeridas', 'recomendaciones_negocio'],
      feeds_active: shared.feedStatus?.filter(f => f.ok).length || 0,
      feeds_total: shared.feedStatus?.length || 0
    },
    needs_backend: {
      description: 'Módulos que requieren configuración OAuth/API en backend ENLAZE',
      modules: [
        { name: 'Gmail', endpoint: '/api/agent/gmail/summary', status: gmailResp.ok ? 'active' : gmailOn ? 'error' : 'pending', what_unlocks: 'Emails prioritarios, respuestas sugeridas, alertas de proveedor' },
        { name: 'Calendar', endpoint: '/api/agent/calendar/summary', status: calendarResp.ok ? 'active' : calendarOn ? 'error' : 'pending', what_unlocks: 'Agenda, huecos libres, recordatorios' },
        { name: 'Reputación', endpoint: '/api/agent/reputation/summary', status: reputationResp.ok ? 'active' : businessOn ? 'error' : 'pending', what_unlocks: 'Reseñas Google, respuestas sugeridas, tendencia' },
        { name: 'Sheets', endpoint: '/api/agent/sheets/summary', status: sheetsResp.ok ? 'active' : sheetsOn ? 'error' : 'pending', what_unlocks: 'Inventario, ventas, alertas de stock' },
        { name: 'Market', endpoint: '/api/agent/market/summary', status: marketResp.ok ? 'active' : 'fallback_public', what_unlocks: 'Señales de mercado adicionales del backend' }
      ]
    },
    workflow_endpoints: [
      { path: '/api/agent/users', role: 'Lista usuarios', required: true },
      { path: '/api/agent/config', role: 'Config usuario', required: true },
      { path: '/api/agent/ingest', role: 'Ingesta payload', required: true }
    ]
  };

  // ── Payload ──
  const payload = {
    user_id: config.user_id,
    business_id: config.business_id || config.user_id,
    business_name: config.business_name,
    business_type: config.business_type,
    city: config.city,
    sector: config.sector || 'comercio_local',
    agent: 'comercio_local',
    version: '6.3',
    timestamp: new Date().toISOString(),
    daily_summary: buildDailySummary(config, { inbox, calendar, reputation, market, radar, competitive, cost_monitor, price_catalog, marketing: { campaigns }, tasks, sheets }),
    recommendations,
    tasks: { items: [...tasks], time_summary: tasks._time_summary || {} },
    price_catalog,
    radar,
    competitive,
    cost_monitor,
    inbox,
    calendar,
    reputation,
    market,
    sheets,
    marketing: { campaigns, upcoming_dates: calendar.next_events || [] },
    automation,
    connections: {
      gmail_connected: inbox.connected,
      google_calendar_connected: calendar.connected,
      google_business_connected: reputation.connected,
      google_sheets_connected: sheets?.connected || false
    }
  };

  delete payload._auth_key;
  delete payload._auth_base_url;
  outputs.push({ json: payload });
}

return outputs;

return $input.all().map(item => {
  const r = item.json || {};
  return {
    json: {
      success: r.success === true || r.ok === true,
      timestamp: r.timestamp || new Date().toISOString(),
      user_id: r.user_id || null,
