    }
  };
});

const stations = $input.first().json.ListaEESSPrecio || [];

let sumDiesel = 0;
let countDiesel = 0;

for (let i = 0; i < Math.min(stations.length, 500); i++) {
  const station = stations[i];
  const dieselStr = station["Precio Gasoleo A"];
  if (dieselStr) {
    const diesel = parseFloat(dieselStr.replace(',', '.'));
    if (!isNaN(diesel)) {
      sumDiesel += diesel;
      countDiesel++;
    }
  }
}

const avgDiesel = countDiesel > 0 ? (sumDiesel / countDiesel) : 1.50;
const pvpLogistica = parseFloat(avgDiesel.toFixed(3));

